import { execSync } from 'child_process';
import fs from 'fs';

function putResult(name, obj) {
  const tok = process.env.GH_TOKEN;
  const url = `https://api.github.com/repos/raimis079-creator/petshop-bridge/contents/screenshots/${name}`;
  let sha = '';
  try { const j = JSON.parse(execSync(`curl -s -H "Authorization: Bearer ${tok}" "${url}"`).toString()); if (j.sha) sha = j.sha; } catch(e) {}
  const content = Buffer.from(JSON.stringify(obj)).toString('base64');
  fs.writeFileSync('/tmp/p.json', JSON.stringify({ message: `r ${name}`, content, ...(sha?{sha}:{}) }));
  execSync(`curl -s -X PUT -H "Authorization: Bearer ${tok}" -d @/tmp/p.json "${url}"`);
}
function sh(c){ try { return execSync(c,{maxBuffer:40*1024*1024}).toString(); } catch(e){ return 'ERR:'+(e.message||'').slice(0,400); } }

const WP_USER = (process.env.WP_USER||'').trim();
const WP_PASS = (process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const AUTH = Buffer.from(WP_USER+':'+WP_PASS).toString('base64');
const API = 'https://dev.avesa.lt/wp-json/code-snippets/v1/snippets';
const out = { ts: new Date().toISOString() };

const FORM_B64 = '';
const PROF_B64 = '';
const UI_B64 = '';

const php = `
add_action('wp_loaded', function(){
	if ( ! isset(\$_GET['ps_m8dep']) ) { return; }
	\$mode = sanitize_key(\$_GET['ps_m8dep']);
	\$base = WP_PLUGIN_DIR . '/petshop-core/';
	\$targets = array(
		'assets/pet-form.js'          => '${FORM_B64}',
		'assets/pet-profile.js'       => '${PROF_B64}',
		'includes/class-pet-ui.php'   => '${UI_B64}',
	);
	\$out = array('mode'=>\$mode);
	if ( \$mode === 'writek9x2' ) {
		foreach (\$targets as \$rel => \$b64) {
			\$f = \$base . \$rel;
			if ( file_exists(\$f) && ! file_exists(\$f . '.bak-20260715') ) {
				copy(\$f, \$f . '.bak-20260715');
			}
			\$data = base64_decode(\$b64);
			\$w = file_put_contents(\$f, \$data);
			\$out['written'][\$rel] = array('bytes'=>\$w, 'md5'=>md5(\$data), 'disk_md5'=>md5_file(\$f));
		}
	} elseif ( \$mode === 'restorek9x2' ) {
		foreach (\$targets as \$rel => \$b64) {
			\$f = \$base . \$rel;
			if ( file_exists(\$f . '.bak-20260715') ) { copy(\$f . '.bak-20260715', \$f); \$out['restored'][] = \$rel; }
		}
	} elseif ( \$mode === 'espk9x2' ) {
		global \$wpdb;
		\$t = \$wpdb->prefix.'ps_event_log';
		\$out['cols'] = \$wpdb->get_col("SHOW COLUMNS FROM {\$t}", 0);
		\$out['rows'] = \$wpdb->get_results("SELECT * FROM {\$t} ORDER BY id DESC LIMIT 15", ARRAY_A);
		\$rq = \$base.'includes/class-retry-queue.php';
		\$out['retry_queue_b64'] = file_exists(\$rq) ? base64_encode(file_get_contents(\$rq)) : 'MISSING';
	}
	header('Content-Type: application/json');
	echo wp_json_encode(\$out);
	exit;
});`;

// 1. Sukuriam snippet
fs.writeFileSync('/tmp/snip.json', JSON.stringify({ name: 'TEMP M8 Deploy v1', code: php, scope: 'global', active: true }));
const create = sh(`curl -sk -X POST -H "Authorization: Basic ${AUTH}" -H "Content-Type: application/json" -d @/tmp/snip.json "${API}"`);
let snipId = 0;
try { const j = JSON.parse(create); snipId = j.id || 0; out.snippet_id = snipId; if(!snipId) out.create_raw = create.slice(0,600); } catch(e) { out.create_raw = create.slice(0,600); }

if (snipId) {
	// 2. WRITE
	const wr = sh('curl -sk --max-time 40 "https://dev.avesa.lt/?ps_m8dep=writek9x2"');
	try { out.write = JSON.parse(wr); } catch(e){ out.write_raw = wr.slice(0,600); }

	// 3. Gyvumo patikra: homepage + account puslapis (fatal error patikra)
	out.alive_home = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/"');
	out.alive_acct = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/my-account/"');

	if (out.alive_home !== '200' || out.alive_acct !== '200') {
		// ROLLBACK
		const rs = sh('curl -sk --max-time 40 "https://dev.avesa.lt/?ps_m8dep=restorek9x2"');
		out.rollback = rs.slice(0,400);
		out.alive_after_rollback = sh('curl -sk -o /dev/null -w "%{http_code}" "https://dev.avesa.lt/"');
	} else {
		// 4. Serveryje deploy'intu failu patikra (cache-bust versija matoma?)
		const js1 = sh('curl -sk --max-time 25 "https://dev.avesa.lt/wp-content/plugins/petshop-core/assets/pet-form.js"');
		out.deployed_form_has_mount = js1.includes('window.PetshopPetForm');
		const js2 = sh('curl -sk --max-time 25 "https://dev.avesa.lt/wp-content/plugins/petshop-core/assets/pet-profile.js"');
		out.deployed_profile_has_host = js2.includes('pspet-form-host');
	}

	// 5. ESP recon (nesvarbu deploy rezultatui - read only)
	const esp = sh('curl -sk --max-time 40 "https://dev.avesa.lt/?ps_m8dep=espk9x2"');
	try { out.esp = JSON.parse(esp); } catch(e){ out.esp_raw = esp.slice(0,600); }

	// 6. ISTRINAM snippet
	sh(`curl -sk -X DELETE -H "Authorization: Basic ${AUTH}" "${API}/${snipId}"`);
	out.delete_verify = sh(`curl -sk -o /dev/null -w "%{http_code}" -H "Authorization: Basic ${AUTH}" "${API}/${snipId}"`);
}

putResult('m8_deploy_1.json', out);
console.log('DONE');
